    /** نصوص الصفحة العامة «تواصل معنا» — من جدول الإعدادات الثابت وليس من كتل الصفحة. */
    private function seedDefaultContactPageCopy(): void
    {
        if (! Schema::hasTable('public_contact_settings')) {
            return;
        }

        $row = PublicContactSettings::query()->first();
        if (! $row) {
            return;
        }
        if (filled($row->intro_text) || filled($row->hint_text) || filled($row->title)) {
            return;
        }

        $row->update([
            'intro_text' => 'يمكنكم التواصل مع فريق ConcreteERP عبر القنوات أدناه للحصول على إجابة بخصوص خطط الاستخدام، تفعيل الشركة، أو أي استفسار تقني عام قبل البدء.',
            'hint_text' => 'يُفضّل ذكر اسم المصنع أو الشركة عند التواصل لتسريع خدمتكم.',
        ]);
    }
